@pkutsenko I have same issue, but for me it happens only if I have component with hook (eg. useRange, useRefinementList, useSortBy, ...) nested in more than 1 level in InstantSearch instance component (In my case Next.js with custom routing). I solved it by adding another one simple "virtual" component with hook directly into InstantSearch instance for each "hook" component.

```
<FiltersSectionWrapper>
	<FiltersWrapper>
                 // components with useRefinementList defined by this component doesn't work with SSR
		<Filters
			showSearchBox
			autoFocusSearchBox={autoFocusSearchBox}
			searchBoxPlaceholder={t('Placeholder')}
			items={[
				{
					type: 'range',
					label: t('FilterOptions.Price'),
					attribute: 'price'
				},
				{
					type: 'toggle',
					label: t('FilterOptions.Available'),
					attribute: 'filterParameters.available'
				},
				{
					type: 'toggle',
					label: t('FilterOptions.FreeDelivery'),
					attribute: 'filterParameters.freeDelivery'
				}
			]}
			excludeAttributes={['categories.slug']}
		/>

		// SSR requires refinement used at this place, without this are refinements ignored on SSR
		<VirtualRefinementList attribute='categories.slug' />
		<VirtualRangeRefinement attribute='price' />
		<VirtualToggleRefinement attribute='filterParameters.available' />
		<VirtualToggleRefinement attribute='filterParameters.freeDelivery' />
	</FiltersWrapper>
	<SortingWrapper>
                // component contains directly useSortBy, so this component works fine also with SSR
		<Sorting items={sortingOptions} />
	</SortingWrapper>
</FiltersSectionWrapper>
```

This is example content of VirtualRefinementList component

```
'use client'

import { useRefinementList, UseRefinementListProps } from 'react-instantsearch'

export default function VirtualRefinementList(props: UseRefinementListProps) {
	useRefinementList(props)
	return null
}
```

But I don't like this solution and I'm almost sure it si not correct usage. It works for now but I want to solve it in more elegant way.

I believe I am on the same page. I had to do a really hacky solution and I don't like mine either ☢️

I have dynamic widgets and do not want to have to babysit a list of hard coded refinement names.

I would rather be able to add new filters inside the Algolia dashboard and not have to deploy a new frontend every time something changes. 

```tsx
// This is needed to ensure that when the page refreshes, any refinements present in the URL
// are re-applied by rendering hidden RefinementList components for each active refinement attribute.
// There is currently no documentation on it for NextJS but hopefully can be removed in the future.
export const VirtualRefinementList = ({ attribute }: { attribute: string }) => {
  useRefinementList({ attribute });

  return null;
};

export const FixRefreshWithHiddenRefinementsFromURL = () => {
  const searchParams = useSearchParams();

  // Extract all active refinement attributes
  const attributesFromSearchParameters =
    extractAlgoliaRefinementAttributes(searchParams);

  return (
    <div className="hidden">
      {attributesFromSearchParameters.map((attribute) => (
        <VirtualRefinementList key={attribute} attribute={attribute} />
      ))}
    </div>
  );
};

export const extractAlgoliaRefinementAttributes = (
  searchParams: URLSearchParams
): string[] => {
  const decodedSearchParams = decodeURIComponent(searchParams.toString());
  const attributes = new Set<string>();

  // Regex to match [refinementList][attribute_name][index]
  const refinementRegex = /\[refinementList\]\[([^\]]+)\]\[\d+\]/g;
  let match;

  while ((match = refinementRegex.exec(decodedSearchParams)) !== null) {
    attributes.add(match[1]);
  }

  return Array.from(attributes);
};
```
